const body = $json.body ?? $json;

// Bot message guard - discard if message is from a bot
if (body.authorIsBot === true) {
  return [];
}

const requiredInput = ['discordUser', 'discordUserId', 'messageTimestamp', 'submittedDate'];
const missingInput = requiredInput.filter((key) => !body[key]);

return [{
  json: {
    discordUser: body.discordUser || 'Unknown user',
    discordUserId: body.discordUserId || '',
    messageTimestamp: body.messageTimestamp || new Date().toISOString(),
    submittedDate: body.submittedDate || new Date().toISOString().slice(0, 10),
    messageId: body.messageId || '',
    channelId: body.channelId || '',
    imageBase64: body.imageBase64 || '',
    mimeType: body.mimeType || 'image/jpeg',
    mockScenario: (body.mockScenario || 'approved').toLowerCase(),
    inputMissingFields: missingInput
  }
}];

// MOCK AI EXTRACTION
// Returns a response shaped exactly like an OpenAI-compatible /chat/completions reply
// so that the downstream "Parse AI Response and Validate" node works unchanged.
//
// The scenario is read from the original webhook body (via Normalize Discord Input):
//   approved (default) -> full valid receipt -> goes to Sheets Append (Approved)
//   pending            -> missing required fields -> goes to Sheets Append (Pending Review)
//   rejected           -> ReceiptDetected: false -> goes to No Receipt branch (no sheet write)
//   unavailable        -> simulates the LLM API being down -> goes to AI Unavailable branch
//   sheetfail          -> valid receipt (like approved), but the real Sheets Append is bypassed
//                         by a downstream mock IF/Code so the SheetAppendFailed branch fires
//                         (hits the Approved fail-IF on the no-missing-fields path)
//   sheetfail-pending  -> receipt with missing required fields (like pending), Sheets Append
//                         is bypassed by the same downstream mock IF/Code so the
//                         SheetAppendFailed branch on the Pending path fires

const input = $('Normalize Discord Input').first().json;
const scenario = (input.mockScenario || 'approved').toLowerCase();

if (scenario === 'unavailable') {
  // Mimic the shape the Parse node interprets as apiUnavailable
  return [{ json: { error: { message: '[MOCK] LLM endpoint unavailable' } } }];
}

let receipt;

if (scenario === 'rejected') {
  receipt = {
    ReceiptDetected: false,
    Merchant: null,
    ReceiptDate: null,
    Currency: null,
    TotalAmount: null,
    VATAmount: null,
    VATIncluded: null,
    Category: null,
    PaymentMethod: null,
    ReceiptId: null,
    BusinessPurpose: null,
    Confidence: 0.0,
    Notes: '[MOCK] Image is not a receipt.'
  };
} else if (scenario === 'pending') {
  // Valid receipt but with missing required fields (Currency + VATAmount blank)
  receipt = {
    ReceiptDetected: true,
    Merchant: 'Mock Cafe',
    ReceiptDate: '28-05-2026',
    Currency: null,
    TotalAmount: 89.0,
    VATAmount: null,
    VATIncluded: 'No',
    Category: 'Food / Meals',
    PaymentMethod: 'Company Card',
    ReceiptId: 'MOCK-PENDING-001',
    BusinessPurpose: 'Mock pending review scenario',
    Confidence: 0.42,
    Notes: '[MOCK] Some required fields are intentionally missing.'
  };
} else if (scenario === 'sheetfail-pending') {
  // missing required fields (Currency + VATAmount) so it routes to the Pending
  // path; the downstream mock IF/Code then injects the Sheets-write failure.
  receipt = {
    ReceiptDetected: true,
    Merchant: 'Mock Sheet-Fail Cafe (Pending)',
    ReceiptDate: '28-05-2026',
    Currency: null,
    TotalAmount: 75.50,
    VATAmount: null,
    VATIncluded: 'No',
    Category: 'Food / Meals',
    PaymentMethod: 'Company Card',
    ReceiptId: 'MOCK-SHEETFAIL-PENDING-001',
    BusinessPurpose: 'Mock sheet-write failure on Pending path',
    Confidence: 0.42,
    Notes: '[MOCK] Pending-shaped receipt — Sheets Append will be mocked to fail on the Pending path.'
  };
} else if (scenario === 'sheetfail') {
  // valid receipt — the failure is injected downstream by a mock IF/Code
  // node so the real Google Sheets call is bypassed entirely.
  receipt = {
    ReceiptDetected: true,
    Merchant: 'Mock Sheet-Fail Diner',
    ReceiptDate: '28-05-2026',
    Currency: 'DKK',
    TotalAmount: 99.00,
    VATAmount: 19.80,
    VATIncluded: 'Yes',
    Category: 'Food / Meals',
    PaymentMethod: 'Company Card',
    ReceiptId: 'MOCK-SHEETFAIL-001',
    BusinessPurpose: 'Mock sheet-write failure scenario',
    Confidence: 0.95,
    Notes: '[MOCK] Valid receipt — Sheets Append will be mocked to fail downstream.'
  };
} else {
  // approved (default) — full valid receipt
  receipt = {
    ReceiptDetected: true,
    Merchant: 'Mock Coffee Roasters',
    ReceiptDate: '28-05-2026',
    Currency: 'DKK',
    TotalAmount: 125.50,
    VATAmount: 25.10,
    VATIncluded: 'Yes',
    Category: 'Food / Meals',
    PaymentMethod: 'Company Card',
    ReceiptId: 'MOCK-APPROVED-001',
    BusinessPurpose: 'Mock approved scenario — Google Sheets integration test',
    Confidence: 0.99,
    Notes: '[MOCK] Hardcoded valid receipt, no LLM was called.'
  };
}

// Shape matches OpenAI/Anthropic-compatible /chat/completions response
return [{
  json: {
    id: 'mock-cmpl-' + Date.now(),
    object: 'chat.completion',
    model: 'mock-vision-model',
    choices: [
      {
        index: 0,
        finish_reason: 'stop',
        message: {
          role: 'assistant',
          content: JSON.stringify(receipt)
        }
      }
    ],
    usage: { prompt_tokens: 0, completion_tokens: 0, total_tokens: 0 }
  }
}];

const original = $('Normalize Discord Input').first().json;
const response = $json;

function safeString(value) {
  if (value === null || value === undefined) return '';
  return String(value).trim();
}

function parseLlmJson(resp) {
  if (resp.error || resp.message?.includes?.('Error')) {
    return { apiUnavailable: true, invalidJson: false, parseError: null, aiRawText: '', extracted: null };
  }
  const text =
    resp.choices?.[0]?.message?.content ??
    resp.body?.choices?.[0]?.message?.content ??
    resp.data?.choices?.[0]?.message?.content ??
    '';
  if (!text) {
    return { apiUnavailable: true, invalidJson: false, parseError: null, aiRawText: '', extracted: null };
  }
  try {
    const cleaned = text.replace(/^```json\s*/i, '').replace(/```$/i, '').trim();
    return { apiUnavailable: false, invalidJson: false, parseError: null, aiRawText: text, extracted: JSON.parse(cleaned) };
  } catch (error) {
    return { apiUnavailable: false, invalidJson: true, parseError: error.message, aiRawText: text, extracted: { ReceiptDetected: false } };
  }
}

const parsed = parseLlmJson(response);

if (parsed.apiUnavailable) {
  return [{
    json: {
      ...original,
      apiUnavailable: true,
      receiptDetected: false,
      logEvent: 'AIUnavailable',
      logLabel: 'error',
      status: 'Rejected',
      details: '[MOCK] LLM endpoint unreachable or returned no usable response.',
      discordMessage: `⚠️ <@${original.discordUserId}> [MOCK] your receipt could not be processed because the AI service is unavailable. Please try again later.`
    }
  }];
}

if (parsed.invalidJson) {
  const rawHead = (parsed.aiRawText || '').slice(0, 200).replace(/\s+/g, ' ');
  return [{
    json: {
      ...original,
      apiUnavailable: false,
      receiptDetected: false,
      logEvent: 'AIResponseInvalid',
      logLabel: 'error',
      status: 'Rejected',
      details: `[MOCK] AI returned non-JSON output: ${parsed.parseError}. Raw head: ${rawHead}`,
      aiRawText: parsed.aiRawText,
      discordMessage: `❌ <@${original.discordUserId}> [MOCK] the AI response was unreadable. Please re-upload the receipt.`
    }
  }];
}

const ai = parsed.extracted || {};
const receiptDetected = ai.ReceiptDetected === true;

if (!receiptDetected) {
  return [{
    json: {
      ...original,
      apiUnavailable: false,
      receiptDetected: false,
      logEvent: 'NoReceiptDetected',
      logLabel: 'warning',
      status: 'Rejected',
      details: `[MOCK] Image classified as non-receipt. AI notes: ${safeString(ai.Notes) || 'no notes provided'}`,
      aiRawText: parsed.aiRawText,
      discordMessage: `❌ <@${original.discordUserId}> [MOCK] no valid receipt was detected. Please send a new image of the receipt.`
    }
  }];
}

const merged = {
  discordUser: original.discordUser,
  discordUserId: original.discordUserId,
  messageTimestamp: original.messageTimestamp,
  submittedDate: original.submittedDate,
  messageId: original.messageId,
  channelId: original.channelId,
  merchant: safeString(ai.Merchant),
  receiptDate: safeString(ai.ReceiptDate),
  currency: safeString(ai.Currency),
  totalAmount: ai.TotalAmount ?? '',
  vatAmount: ai.VATAmount ?? '',
  vatIncluded: safeString(ai.VATIncluded),
  category: safeString(ai.Category),
  paymentMethod: safeString(ai.PaymentMethod),
  receiptId: safeString(ai.ReceiptId),
  businessPurpose: safeString(ai.BusinessPurpose),
  confidence: ai.Confidence ?? '',
  notes: safeString(ai.Notes)
};

const requiredFields = [
  ['Merchant', merged.merchant],
  ['Receipt Date', merged.receiptDate],
  ['Currency', merged.currency],
  ['Total Amount', merged.totalAmount],
  ['VAT Amount', merged.vatAmount],
  ['Category', merged.category],
  ['Payment Method', merged.paymentMethod]
];

const missingFields = requiredFields
  .filter(([_, value]) => value === '' || value === null || value === undefined)
  .map(([field]) => field);

const hasMissingFields = missingFields.length > 0;
const status = hasMissingFields ? 'Pending Review' : 'Approved by Bot';

const aiSummary = `Merchant: ${merged.merchant || '(blank)'}, Total: ${merged.totalAmount === '' ? '(blank)' : merged.totalAmount} ${merged.currency || ''}, Date: ${merged.receiptDate || '(blank)'}, Confidence: ${merged.confidence === '' ? '(blank)' : merged.confidence}`;
const aiResponseDetails = `[MOCK] Receipt parsed — ${aiSummary}`;
const missingDetails = `[MOCK] Routed to Pending Review. Missing fields: ${missingFields.join(', ')}`;

const discordMessage = hasMissingFields
  ? `🟡 <@${merged.discordUserId}> [MOCK] your receipt was detected, but it is missing required data.\n\n**Status:** Pending Review\n**Missing:** ${missingFields.join(', ')}\n\nPlease re-upload the receipt with the missing information.`
  : `✅ <@${merged.discordUserId}> [MOCK] your receipt was processed successfully.\n\n**Status:** Approved by Bot\n**Merchant:** ${merged.merchant}\n**Amount:** ${merged.totalAmount} ${merged.currency}\n**Category:** ${merged.category}`;

return [{
  json: {
    ...merged,
    apiUnavailable: false,
    receiptDetected: true,
    hasMissingFields,
    missingFields,
    status,
    details: aiResponseDetails,
    missingDetails,
    aiRawText: parsed.aiRawText,
    logEvent: 'AIResponseReceived',
    logLabel: 'info',
    discordMessage
  }
}];

// MOCK: emit a payload with $json.error set so the downstream
// "Sheets Write Failed? (Pending)" IF routes to the SheetAppendFailed branch.
// No real Google Sheets call happens on this path.
return [{
  json: {
    error: '[MOCK] Forced Google Sheets write failure for testing.'
  }
}];

// MOCK: emit a payload with $json.error set so the downstream
// "Sheets Write Failed? (Approved)" IF routes to the SheetAppendFailed branch.
// No real Google Sheets call happens on this path.
return [{
  json: {
    error: '[MOCK] Forced Google Sheets write failure for testing.'
  }
}];
